changeSet.sql:
ALTER TABLE campaign ADD COLUMN IF NOT EXISTS raw_data jsonb;
ALTER TABLE ad_set   ADD COLUMN IF NOT EXISTS raw_data jsonb;
ALTER TABLE ad       ADD COLUMN IF NOT EXISTS raw_data jsonb;

rollback.sql:
ALTER TABLE campaign DROP COLUMN IF EXISTS raw_data;
